def _validate_saml_response_structure(root):
    """
    Performs basic structural validation of the SAML Response XML.
    """
    if not root.tag == f"{{{SAML_PROTOCOL_NS}}}Response":
        logger.error(f"Root element is not a SAML Response: {root.tag}")
        return False

    # Check for Status element
    status_element = root.find(f"{{{SAML_PROTOCOL_NS}}}Status")
    if status_element is None:
        logger.error("SAML Response missing Status element.")
        return False

    status_code_element = status_element.find(f"{{{SAML_PROTOCOL_NS}}}StatusCode")
    if status_code_element is None:
        logger.error("SAML Response Status missing StatusCode element.")
        return False

    status_value = status_code_element.get('Value')
    if status_value != "urn:oasis:names:tc:SAML:2.0:status:Success":
        logger.error(f"SAML Response indicates non-success status: {status_value}")
        return False

    # Check for Assertion element
    assertion_element = root.find(f"{{{SAML_ASSERTION_NS}}}Assertion")
    if assertion_element is None:
        logger.error("SAML Response missing Assertion element.")
        return False

    return True

def _extract_saml_attributes(assertion_element):
    """
    Extracts attributes from the SAML Assertion.
    """
    attributes = {}
    attribute_statement = assertion_element.find(f"{{{SAML_ASSERTION_NS}}}AttributeStatement")
    if attribute_statement:
        for attr in attribute_statement.findall(f"{{{SAML_ASSERTION_NS}}}Attribute"):
            name = attr.get('Name')
            if name:
                for value_elem in attr.findall(f"{{{SAML_ASSERTION_NS}}}AttributeValue"):
                    if value_elem.text:
                        # For simplicity, if multiple values, take the first one.
                        # Can be extended to handle multi-valued attributes.
                        attributes[name] = value_elem.text
                        break
    return attributes

def _get_name_id(assertion_element):
    """
    Extracts the NameID from the SAML Assertion's Subject.
    """
    subject = assertion_element.find(f"{{{SAML_ASSERTION_NS}}}Subject")
    if subject:
        name_id = subject.find(f"{{{SAML_ASSERTION_NS}}}NameID")
        if name_id is not None and name_id.text:
            return name_id.text
    return None

