    if not _validate_saml_response_structure(root):
        return HttpResponseBadRequest("SAML Response failed structural validation.")

    assertion_element = root.find(f"{{{SAML_ASSERTION_NS}}}Assertion")
    if assertion_element is None:
        logger.error("SAML Response Assertion element not found after basic validation.")
        return HttpResponseBadRequest("SAML Assertion missing.")

